class Solution(object):
    def answerQueries(self, nums, queries):
        nums.sort()
        prefix_sum = [0]
        for num in nums:
            prefix_sum.append(prefix_sum[-1] + num)
        result = []
        for q in queries:
            for i in range(len(prefix_sum)):
                if prefix_sum[i] > q:
                    result.append(i - 1)
                    break
            else:
                result.append(len(nums))
        return result
